FUNCTION SelectBestPath(candidateRoutes)
BEGIN
 // Filter invalid routes first
 validRoutes ← REMOVE_INVALID(candidateRoutes)
 IF validRoutes IS EMPTY THEN
 RETURN NULL
 ENDIF

 // Step 1: Highest LOCAL-PREF
 bestRoutes ← FIND_HIGHEST_LOCAL_PREF(validRoutes)

 // Step 2: Shortest AS-PATH length
 bestRoutes ← FIND_SHORTEST_AS_PATH(bestRoutes)

 // Step 3: Lowest MED
 bestRoutes ← FIND_LOWEST_MED(bestRoutes)

 // Step 4: Prefer eBGP over iBGP
 bestRoutes ← FILTER_EBGP_ONLY(bestRoutes)

 // Step 5: Lowest IGP cost to NEXT-HOP
 bestRoutes ← FIND_LOWEST_IGP_COST(bestRoutes)

 // Step 6: Lowest BGP Router ID (tiebreaker)
 bestRoute ← FIND_LOWEST_ROUTER_ID(bestRoutes)

 RETURN bestRoute
END
